noncompliant:
void func() {
  int value = 42;
  int *ptr = &value; // Noncompliant: ptr not modified, should be const
  printf("%d", *ptr);
}

void process() {
  char buffer[100] = "hello";
  char *str = buffer; // Noncompliant: str not modified, should be const
  printf("%s", str);
}

compliant:
void func() {
  int value = 42;
  const int *ptr = &value; // Compliant: ptr declared as const
  printf("%d", *ptr);
}

void process() {
  char buffer[100] = "hello";
  const char *str = buffer; // Compliant: str declared as const
  printf("%s", str);
}
